<template>
  <div class="maintenance-platform">
    <!-- 头部导航 -->
    <div class="header">
      <div class="header-left">
        <h1>设备运维管理平台</h1>
        <div class="status-indicator" :class="overallStatus">
          {{ statusText }}
        </div>
      </div>
      <div class="header-right">
        <button class="back-btn" @click="goBack">
          <i class="fas fa-arrow-left"></i> 返回大屏
        </button>
        <div class="time-display">{{ currentTime }}</div>
      </div>
    </div>

    <!-- 模块选择器 -->
    <div class="module-selector">
      <div 
        v-for="module in modules" 
        :key="module.id"
        :class="['module-card', { active: activeModule === module.id }]"
        @click="switchModule(module.id)"
      >
        <div class="module-icon">
          <i :class="module.icon"></i>
        </div>
        <div class="module-info">
          <h3>{{ module.name }}</h3>
          <p>{{ module.description }}</p>
        </div>
        <div class="module-status" :class="module.status">
          {{ module.statusText }}
        </div>
      </div>
    </div>

    <!-- 内容区域 -->
    <div class="content-area">
      <!-- 预测预警模块 -->
      <div v-if="activeModule === 'prediction'" class="module-content">
        <PredictionWarning />
      </div>

      <!-- 良率分析模块 -->
      <div v-if="activeModule === 'yield'" class="module-content">
        <YieldAnalysis />
      </div>

      <!-- 故障诊断模块 -->
      <div v-if="activeModule === 'diagnosis'" class="module-content">
        <FaultDiagnosis />
      </div>
    </div>

    <!-- 全局预警弹窗 -->
    <div v-if="showGlobalAlert" class="global-alert-overlay" @click="closeGlobalAlert">
      <div class="global-alert" @click.stop>
        <div class="alert-header">
          <h3>⚠️ 系统预警</h3>
          <button class="close-btn" @click="closeGlobalAlert">×</button>
        </div>
        <div class="alert-content">
          <div v-for="alert in globalAlerts" :key="alert.id" class="alert-item">
            <div class="alert-icon" :class="alert.level">
              <i :class="alert.icon"></i>
            </div>
            <div class="alert-text">
              <h4>{{ alert.title }}</h4>
              <p>{{ alert.message }}</p>
              <span class="alert-time">{{ alert.time }}</span>
            </div>
          </div>
        </div>
        <div class="alert-actions">
          <button class="btn-primary" @click="handleAlert">立即处理</button>
          <button class="btn-secondary" @click="closeGlobalAlert">稍后处理</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted, onUnmounted } from 'vue'
import router from '../router'
import axios from 'axios'
import PredictionWarning from '../components/maintenance/PredictionWarning.vue'
import YieldAnalysis from '../components/maintenance/YieldAnalysis.vue'
import FaultDiagnosis from '../components/maintenance/FaultDiagnosis.vue'

export default {
  name: 'MaintenancePlatform',
  components: {
    PredictionWarning,
    YieldAnalysis,
    FaultDiagnosis
  },
  setup() {
    const activeModule = ref('prediction')
    const currentTime = ref('')
    const showGlobalAlert = ref(false)
    const globalAlerts = ref([])
    const realtimeData = ref({})
    const timing = ref(null)

    // 模块配置
    const modules = ref([
      {
        id: 'prediction',
        name: '预测预警',
        description: '设备状态预测与预警管理',
        icon: 'fas fa-chart-line',
        status: 'normal',
        statusText: '正常'
      },
      {
        id: 'yield',
        name: '良率分析',
        description: '产品质量分析与良率统计',
        icon: 'fas fa-percentage',
        status: 'normal',
        statusText: '正常'
      },
      {
        id: 'diagnosis',
        name: '故障诊断',
        description: '设备故障诊断与原因分析',
        icon: 'fas fa-stethoscope',
        status: 'normal',
        statusText: '正常'
      }
    ])

    // 计算属性
    const overallStatus = computed(() => {
      const hasWarning = modules.value.some(m => m.status === 'warning')
      const hasError = modules.value.some(m => m.status === 'error')
      
      if (hasError) return 'error'
      if (hasWarning) return 'warning'
      return 'normal'
    })

    const statusText = computed(() => {
      switch (overallStatus.value) {
        case 'error': return '系统异常'
        case 'warning': return '存在预警'
        case 'normal': return '运行正常'
        default: return '未知状态'
      }
    })

    // 方法
    const switchModule = (moduleId) => {
      activeModule.value = moduleId
    }

    const goBack = () => {
      router.push('/')
    }

    const updateTime = () => {
      const now = new Date()
      currentTime.value = now.toLocaleString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      })
    }

    const fetchRealtimeData = async () => {
      try {
        const response = await axios.get('/api/maintenance/realtime')
        if (response.data.status === 'success') {
          realtimeData.value = response.data.data
          checkAlerts(response.data.warnings || [])
        }
      } catch (error) {
        console.error('获取实时数据失败:', error)
      }
    }

    const checkAlerts = (warnings) => {
      if (warnings.length > 0) {
        globalAlerts.value = warnings.map((warning, index) => ({
          id: index,
          title: '设备预警',
          message: warning,
          level: 'warning',
          icon: 'fas fa-exclamation-triangle',
          time: new Date().toLocaleTimeString()
        }))
        showGlobalAlert.value = true
      }
    }

    const closeGlobalAlert = () => {
      showGlobalAlert.value = false
      globalAlerts.value = []
    }

    const handleAlert = () => {
      // 处理预警逻辑
      console.log('处理预警')
      closeGlobalAlert()
    }

    // 生命周期
    onMounted(() => {
      updateTime()
      timing.value = setInterval(updateTime, 1000)
      fetchRealtimeData()
      
      // 每30秒获取一次实时数据
      setInterval(fetchRealtimeData, 30000)
    })

    onUnmounted(() => {
      if (timing.value) {
        clearInterval(timing.value)
      }
    })

    return {
      activeModule,
      currentTime,
      showGlobalAlert,
      globalAlerts,
      modules,
      overallStatus,
      statusText,
      switchModule,
      goBack,
      closeGlobalAlert,
      handleAlert
    }
  }
}
</script>

<style scoped>
.maintenance-platform {
  min-height: 100vh;
  background: linear-gradient(135deg, #0c1426 0%, #1a2332 100%);
  color: #fff;
  font-family: 'Arial', sans-serif;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 30px;
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.header-left {
  display: flex;
  align-items: center;
  gap: 20px;
}

.header-left h1 {
  margin: 0;
  font-size: 28px;
  font-weight: bold;
  background: linear-gradient(45deg, #00d4ff, #5b73ff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.status-indicator {
  padding: 8px 16px;
  border-radius: 20px;
  font-weight: bold;
  font-size: 14px;
}

.status-indicator.normal {
  background: linear-gradient(45deg, #4CAF50, #45a049);
  color: white;
}

.status-indicator.warning {
  background: linear-gradient(45deg, #FF9800, #f57c00);
  color: white;
}

.status-indicator.error {
  background: linear-gradient(45deg, #F44336, #d32f2f);
  color: white;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 20px;
}

.back-btn {
  padding: 10px 20px;
  background: linear-gradient(45deg, #ff6b6b, #ee5a24);
  border: none;
  border-radius: 8px;
  color: white;
  cursor: pointer;
  font-size: 14px;
  font-weight: bold;
  transition: all 0.3s ease;
}

.back-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 15px rgba(255, 107, 107, 0.4);
}

.time-display {
  font-size: 16px;
  font-weight: bold;
  color: #00d4ff;
}

.module-selector {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 20px;
  padding: 30px;
}

.module-card {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  padding: 20px;
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}

.module-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent);
  transition: left 0.5s;
}

.module-card:hover::before {
  left: 100%;
}

.module-card:hover {
  transform: translateY(-5px);
  border-color: #00d4ff;
  box-shadow: 0 10px 30px rgba(0, 212, 255, 0.2);
}

.module-card.active {
  border-color: #00d4ff;
  background: rgba(0, 212, 255, 0.1);
  box-shadow: 0 10px 30px rgba(0, 212, 255, 0.3);
}

.module-icon {
  font-size: 32px;
  color: #00d4ff;
  margin-bottom: 15px;
}

.module-info h3 {
  margin: 0 0 8px 0;
  font-size: 20px;
  font-weight: bold;
}

.module-info p {
  margin: 0 0 15px 0;
  color: #b0b0b0;
  font-size: 14px;
}

.module-status {
  position: absolute;
  top: 15px;
  right: 15px;
  padding: 4px 12px;
  border-radius: 12px;
  font-size: 12px;
  font-weight: bold;
}

.module-status.normal {
  background: #4CAF50;
  color: white;
}

.module-status.warning {
  background: #FF9800;
  color: white;
}

.module-status.error {
  background: #F44336;
  color: white;
}

.content-area {
  padding: 0 30px 30px;
}

.module-content {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 12px;
  padding: 20px;
  min-height: 600px;
}

.global-alert-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.8);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
}

.global-alert {
  background: linear-gradient(135deg, #1a2332 0%, #0c1426 100%);
  border-radius: 12px;
  padding: 30px;
  max-width: 500px;
  width: 90%;
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
}

.alert-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  padding-bottom: 15px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.alert-header h3 {
  margin: 0;
  color: #ff6b6b;
  font-size: 20px;
}

.close-btn {
  background: none;
  border: none;
  color: #b0b0b0;
  font-size: 24px;
  cursor: pointer;
  padding: 0;
  width: 30px;
  height: 30px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.close-btn:hover {
  color: #fff;
}

.alert-content {
  margin-bottom: 20px;
}

.alert-item {
  display: flex;
  align-items: flex-start;
  gap: 15px;
  margin-bottom: 15px;
  padding: 15px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
}

.alert-icon {
  font-size: 20px;
  margin-top: 2px;
}

.alert-icon.warning {
  color: #ff9800;
}

.alert-icon.error {
  color: #f44336;
}

.alert-text h4 {
  margin: 0 0 5px 0;
  font-size: 16px;
  color: #fff;
}

.alert-text p {
  margin: 0 0 5px 0;
  color: #b0b0b0;
  font-size: 14px;
}

.alert-time {
  font-size: 12px;
  color: #666;
}

.alert-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
}

.btn-primary, .btn-secondary {
  padding: 10px 20px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-size: 14px;
  font-weight: bold;
  transition: all 0.3s ease;
}

.btn-primary {
  background: linear-gradient(45deg, #ff6b6b, #ee5a24);
  color: white;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 15px rgba(255, 107, 107, 0.4);
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.1);
  color: #b0b0b0;
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.2);
  color: #fff;
}

@media (max-width: 768px) {
  .header {
    flex-direction: column;
    gap: 15px;
    text-align: center;
  }
  
  .module-selector {
    grid-template-columns: 1fr;
    padding: 20px;
  }
  
  .content-area {
    padding: 0 20px 20px;
  }
}
</style>
