                  {{ realtimeData.vibration_Z?.toFixed(3) || '0.000' }}
                </div>
                <div class="threshold">阈值: {{ VIBRATION_THRESHOLD.toFixed(1) }}</div>
              </div>
            </div>
          </div>
        </div>

        <!-- 噪声监控 -->
        <div class="monitor-card">
          <div class="card-header">
