              <div class="noise-value" :class="getNoiseClass()">
                {{ realtimeData.noise_X || 0 }} dB
              </div>
              <div class="noise-threshold">阈值: {{ NOISE_THRESHOLD }} dB</div>
              <div class="noise-bar">
                <div class="noise-fill" :style="{ width: getNoisePercentage() + '%' }"></div>
              </div>
            </div>
          </div>
        </div>

        <!-- 预测结果 -->
