              <span class="label">X轴预测误差:</span>
              <span class="value" :class="getPredictionClass('x')">
                {{ predictionData.pred_x?.toFixed(2) || '0.00' }} mm
              </span>
            </div>
            <div class="prediction-item">
              <span class="label">Y轴预测误差:</span>
              <span class="value" :class="getPredictionClass('y')">
