          </div>
        </div>
      </div>
    </div>

    <!-- 预警弹窗 -->
    <div v-if="showAlertModal" class="alert-modal-overlay" @click="closeAlertModal">
      <div class="alert-modal" @click.stop>
        <div class="modal-header">
          <h3>🚨 设备预警</h3>
          <button class="close-btn" @click="closeAlertModal">×</button>
        </div>
