              <p>{{ currentAlert.message }}</p>
              <div class="alert-values">
                <div v-if="currentAlert.type === 'vibration'">
                  <span>X轴振动: {{ realtimeData.vibration_X?.toFixed(3) }}</span>
                  <span>Z轴振动: {{ realtimeData.vibration_Z?.toFixed(3) }}</span>
                </div>
