                  <span>预测误差: {{ predictionData.pred_x?.toFixed(2) }}mm</span>
                  <span>良率: {{ predictionData.yield_rate?.toFixed(1) }}%</span>
                </div>
              </div>
            </div>
          </div>
        </div>
        <div class="modal-actions">
          <button class="btn-primary" @click="handleAlert">立即处理</button>
          <button class="btn-secondary" @click="closeAlertModal">稍后处理</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted, onUnmounted } from 'vue'
import axios from 'axios'

export default {
  name: 'PredictionWarning',
  setup() {
    const VIBRATION_THRESHOLD = 16
    const NOISE_THRESHOLD = 90
    const realtimeData = ref({})
    const predictionData = ref({})
    const alertHistory = ref([])
    const showAlertModal = ref(false)
    const currentAlert = ref({})
    const timing = ref(null)
    const predictionTimer = ref(null)

    // 计算属性
    const vibrationAlert = computed(() => {
      return (realtimeData.value.vibration_X > VIBRATION_THRESHOLD) ||
             (realtimeData.value.vibration_Z > VIBRATION_THRESHOLD)
    })

    const noiseAlert = computed(() => {
      return realtimeData.value.noise_X > NOISE_THRESHOLD
    })

    const predictionAlert = computed(() => {
      return (Math.abs(predictionData.value.pred_x) > 50) || 
             (Math.abs(predictionData.value.pred_y) > 50) || 
             (predictionData.value.yield_rate < 90)
    })

    const overallStatus = computed(() => {
      if (vibrationAlert.value || noiseAlert.value || predictionAlert.value) {
        return 'warning'
      }
      return 'normal'
    })

    const statusText = computed(() => {
      return overallStatus.value === 'warning' ? '存在预警' : '运行正常'
    })

    // 方法
    const getVibrationClass = (axis) => {
      const value = axis === 'x' ? realtimeData.value.vibration_X : realtimeData.value.vibration_Z
      const threshold = VIBRATION_THRESHOLD
      return value > threshold ? 'danger' : value > threshold * 0.8 ? 'warning' : 'normal'
    }

    const getNoiseClass = () => {
      const value = realtimeData.value.noise_X || 0
      return value > NOISE_THRESHOLD ? 'danger' : value > NOISE_THRESHOLD * 0.8 ? 'warning' : 'normal'
    }

    const getNoisePercentage = () => {
      const value = realtimeData.value.noise_X || 0
      return Math.min((value / NOISE_THRESHOLD) * 100, 100)
    }

    const getPredictionClass = (axis) => {
      const value = axis === 'x' ? predictionData.value.pred_x : predictionData.value.pred_y
      return Math.abs(value) > 50 ? 'danger' : Math.abs(value) > 30 ? 'warning' : 'normal'
    }

    const getYieldClass = () => {
      const value = predictionData.value.yield_rate || 0
      return value < 90 ? 'danger' : value < 95 ? 'warning' : 'normal'
    }

    const fetchAlertHistory = async () => {
      try {
        const response = await axios.get('/api/maintenance/prediction/alerts')
        if (response.data.status === 'success') {
          alertHistory.value = response.data.data || []
        }
      } catch (error) {
        console.error('获取预警历史失败:', error)
      }
    }

    const fetchRealtimeData = async () => {
      try {
        const response = await axios.get('/api/maintenance/realtime', {
          params: { interval_seconds: 1 }
        })
        if (response.data.status === 'success') {
          realtimeData.value = response.data.data
          checkAlerts()
          fetchAlertHistory()
        }
      } catch (error) {
        console.error('获取实时数据失败:', error)
      }
    }

    const fetchPredictionData = async () => {
      try {
        const response = await axios.post('/api/maintenance/predict', {
          start_time: new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString(),
          end_time: new Date().toISOString()
        })
        if (response.data.status === 'success') {
          const data = response.data.data
          predictionData.value = {
            pred_x: data.predictions[0]?.pred_x || 0,
            pred_y: data.predictions[0]?.pred_y || 0,
            yield_rate: data.yield_stats?.yield_rate || 0
          }
          checkPredictionAlerts(data.warnings || [])
          fetchAlertHistory()
        }
      } catch (error) {
        console.error('获取预测数据失败:', error)
      }
    }

    const checkAlerts = () => {
      const alerts = []
      
      if (vibrationAlert.value) {
        alerts.push({
          type: 'vibration',
          level: 'warning',
          icon: 'fas fa-exclamation-triangle',
          title: '振动预警',
          message: '设备振动值超出正常范围，请检查设备状态'
        })
      }

      if (noiseAlert.value) {
        alerts.push({
          type: 'noise',
          level: 'warning',
          icon: 'fas fa-volume-up',
          title: '噪声预警',
          message: '环境噪声超出安全阈值，请检查设备运行环境'
        })
      }

      if (alerts.length > 0) {
        showAlert(alerts[0])
      }
    }

    const checkPredictionAlerts = (warnings) => {
      if (warnings.length > 0) {
        showAlert({
          type: 'prediction',
          level: 'warning',
          icon: 'fas fa-chart-line',
          title: '预测预警',
          message: warnings[0]
        })
      }
    }

    const showAlert = (alert) => {
      currentAlert.value = alert
      showAlertModal.value = true
    }

    const closeAlertModal = () => {
      showAlertModal.value = false
      currentAlert.value = {}
    }

    const handleAlert = () => {
      closeAlertModal()
    }

    // 生命周期
    onMounted(() => {
      fetchRealtimeData()
      fetchPredictionData()
      fetchAlertHistory()
      
      timing.value = setInterval(() => {
        fetchRealtimeData()
      }, 3000)
      
      predictionTimer.value = setInterval(fetchPredictionData, 60000)
    })

    onUnmounted(() => {
      if (timing.value) {
        clearInterval(timing.value)
      }
      if (predictionTimer.value) {
        clearInterval(predictionTimer.value)
      }
    })

    return {
      VIBRATION_THRESHOLD,
      NOISE_THRESHOLD,
      realtimeData,
      predictionData,
      alertHistory,
      showAlertModal,
      currentAlert,
      vibrationAlert,
      noiseAlert,
      predictionAlert,
      overallStatus,
      statusText,
      getVibrationClass,
      getNoiseClass,
      getNoisePercentage,
      getPredictionClass,
      getYieldClass,
      fetchAlertHistory,
      closeAlertModal,
      handleAlert
    }
  }
}
</script>

