<template>
  <div class="yield-analysis">
    <div class="header">
      <h2>良率分析系统</h2>
      <div class="status-indicator" :class="overallStatus">
        {{ statusText }}
      </div>
    </div>

    <!-- 良率统计面板 -->
    <div class="stats-panel">
      <div class="stats-grid">
        <div class="stat-card">
          <div class="stat-icon">
            <i class="fas fa-percentage"></i>
          </div>
          <div class="stat-content">
            <div class="stat-value" :class="getYieldClass()">
              {{ yieldData.quality_rate?.toFixed(1) || '0.0' }}%
            </div>
            <div class="stat-label">当前良率</div>
          </div>
        </div>

        <div class="stat-card">
          <div class="stat-icon">
            <i class="fas fa-chart-line"></i>
          </div>
          <div class="stat-content">
            <div class="stat-value">{{ yieldData.total_production || 0 }}</div>
            <div class="stat-label">总产量</div>
          </div>
        </div>

        <div class="stat-card">
          <div class="stat-icon">
            <i class="fas fa-check-circle"></i>
          </div>
          <div class="stat-content">
            <div class="stat-value">{{ yieldData.quality_products || 0 }}</div>
            <div class="stat-label">良品数量</div>
          </div>
        </div>

        <div class="stat-card">
          <div class="stat-icon">
            <i class="fas fa-times-circle"></i>
          </div>
          <div class="stat-content">
            <div class="stat-value">{{ yieldData.defect_count || 0 }}</div>
            <div class="stat-label">不良品数量</div>
          </div>
        </div>
      </div>
    </div>

    <!-- 良率趋势图表 -->
    <div class="chart-section">
      <div class="chart-container">
        <h3>良率趋势分析</h3>
        <div class="chart-placeholder">
          <div class="trend-chart">
            <div 
              v-for="(item, index) in trendData" 
              :key="index"
              class="trend-bar"
              :style="{ height: item.rate + '%' }"
              :class="getTrendClass(item.rate)"
            >
              <div class="bar-value">{{ item.rate.toFixed(1) }}%</div>
            </div>
          </div>
          <div class="chart-labels">
            <span v-for="(item, index) in trendData" :key="index" class="label">
              {{ item.date }}
            </span>
          </div>
        </div>
      </div>

      <div class="analysis-summary">
        <h3>分析总结</h3>
        <div class="summary-content">
          <div class="summary-item">
            <span class="label">平均良率:</span>
            <span class="value">{{ averageYield.toFixed(1) }}%</span>
          </div>
          <div class="summary-item">
            <span class="label">最高良率:</span>
            <span class="value">{{ maxYield.toFixed(1) }}%</span>
          </div>
          <div class="summary-item">
            <span class="label">最低良率:</span>
            <span class="value">{{ minYield.toFixed(1) }}%</span>
          </div>
          <div class="summary-item">
            <span class="label">趋势:</span>
            <span class="value" :class="getTrendClass(trendDirection)">
              {{ trendText }}
            </span>
          </div>
        </div>
      </div>
    </div>

    <!-- 质量分析详情 -->
    <div class="quality-details">
      <h3>质量分析详情</h3>
      <div class="details-grid">
        <div class="detail-card">
          <h4>缺陷类型分析</h4>
          <div class="defect-list">
            <div v-for="defect in defectTypes" :key="defect.type" class="defect-item">
              <span class="defect-type">{{ defect.type }}</span>
              <span class="defect-count">{{ defect.count }}</span>
              <div class="defect-bar">
                <div 
                  class="defect-fill" 
                  :style="{ width: (defect.count / maxDefectCount * 100) + '%' }"
                ></div>
              </div>
            </div>
          </div>
        </div>

        <div class="detail-card">
          <h4>生产线良率对比</h4>
          <div class="line-comparison">
            <div v-for="line in productionLines" :key="line.name" class="line-item">
              <span class="line-name">{{ line.name }}</span>
              <span class="line-rate" :class="getLineClass(line.rate)">
                {{ line.rate.toFixed(1) }}%
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted } from 'vue'
import axios from 'axios'

export default {
  name: 'YieldAnalysis',
  setup() {
    const yieldData = ref({})
    const trendData = ref([])
    const defectTypes = ref([])
    const productionLines = ref([])

    // 计算属性
    const averageYield = computed(() => {
      if (trendData.value.length === 0) return 0
      const sum = trendData.value.reduce((acc, item) => acc + item.rate, 0)
      return sum / trendData.value.length
    })

    const maxYield = computed(() => {
      if (trendData.value.length === 0) return 0
      return Math.max(...trendData.value.map(item => item.rate))
    })

    const minYield = computed(() => {
      if (trendData.value.length === 0) return 0
      return Math.min(...trendData.value.map(item => item.rate))
    })

    const trendDirection = computed(() => {
      if (trendData.value.length < 2) return 0
      const recent = trendData.value.slice(-3)
      const older = trendData.value.slice(-6, -3)
      if (recent.length === 0 || older.length === 0) return 0
      
      const recentAvg = recent.reduce((acc, item) => acc + item.rate, 0) / recent.length
      const olderAvg = older.reduce((acc, item) => acc + item.rate, 0) / older.length
      return recentAvg - olderAvg
    })

    const trendText = computed(() => {
      const direction = trendDirection.value
      if (direction > 1) return '上升'
      if (direction < -1) return '下降'
      return '稳定'
    })

    const overallStatus = computed(() => {
      const currentRate = yieldData.value.quality_rate || 0
      if (currentRate < 90) return 'error'
      if (currentRate < 95) return 'warning'
      return 'normal'
    })

    const statusText = computed(() => {
      switch (overallStatus.value) {
        case 'error': return '良率过低'
        case 'warning': return '良率偏低'
        case 'normal': return '良率正常'
        default: return '未知状态'
      }
    })

    const maxDefectCount = computed(() => {
      if (defectTypes.value.length === 0) return 1
      return Math.max(...defectTypes.value.map(d => d.count))
    })

    // 方法
    const getYieldClass = () => {
      const rate = yieldData.value.quality_rate || 0
      if (rate < 90) return 'danger'
      if (rate < 95) return 'warning'
      return 'normal'
    }

    const getTrendClass = (rate) => {
      if (rate < 90) return 'danger'
      if (rate < 95) return 'warning'
      return 'normal'
    }

    const getLineClass = (rate) => {
      if (rate < 90) return 'danger'
      if (rate < 95) return 'warning'
      return 'normal'
    }

    const fetchYieldData = async () => {
      try {
        const response = await axios.get('/api/production')
        yieldData.value = response.data
      } catch (error) {
        console.error('获取良率数据失败:', error)
      }
    }

    const fetchTrendData = async () => {
      try {
        const response = await axios.get('/api/production_daily')
        const data = response.data.slice(-7) // 最近7天
        trendData.value = data.map(item => ({
          date: item.date,
          rate: item.quality_rate
        }))
      } catch (error) {
        console.error('获取趋势数据失败:', error)
      }
    }

    const fetchQualityAnalysis = async () => {
      try {
        const response = await axios.get('/api/quality_analysis')
        const data = response.data
        
        // 模拟缺陷类型数据
        defectTypes.value = [
          { type: '尺寸偏差', count: Math.floor(data.defect_rate * 0.3) },
          { type: '表面缺陷', count: Math.floor(data.defect_rate * 0.25) },
          { type: '功能异常', count: Math.floor(data.defect_rate * 0.2) },
          { type: '外观不良', count: Math.floor(data.defect_rate * 0.15) },
          { type: '其他', count: Math.floor(data.defect_rate * 0.1) }
        ]

        // 模拟生产线数据
        productionLines.value = [
          { name: '生产线A', rate: data.quality_rate + Math.random() * 4 - 2 },
          { name: '生产线B', rate: data.quality_rate + Math.random() * 4 - 2 },
          { name: '生产线C', rate: data.quality_rate + Math.random() * 4 - 2 },
          { name: '生产线D', rate: data.quality_rate + Math.random() * 4 - 2 }
        ]
      } catch (error) {
        console.error('获取质量分析数据失败:', error)
      }
    }

    onMounted(() => {
      fetchYieldData()
      fetchTrendData()
      fetchQualityAnalysis()
    })

    return {
      yieldData,
      trendData,
      defectTypes,
      productionLines,
      averageYield,
      maxYield,
      minYield,
      trendDirection,
      trendText,
      overallStatus,
      statusText,
      maxDefectCount,
      getYieldClass,
      getTrendClass,
      getLineClass
    }
  }
}
</script>

