<template>
  <div class="fault-diagnosis">
    <div class="header">
      <h2>故障诊断系统</h2>
      <div class="status-indicator" :class="diagnosisStatus">
        {{ statusText }}
      </div>
    </div>

    <!-- 诊断结果 -->
    <div class="diagnosis-result">
      <h3>诊断结果</h3>
      <div class="result-card" :class="resultCardClass">
        <p>{{ diagnosisResult }}</p>
      </div>
    </div>

    <!-- 神经网络分类预测 -->
    <div class="neural-network-prediction">
      <h3>神经网络分类预测</h3>
      <div class="prediction-grid">
        <div class="prediction-card">
          <h4>故障类别概率分布</h4>
          <div class="probability-chart">
            <div 
              v-for="(category, index) in faultCategories" 
              :key="index"
              class="probability-item"
            >
              <div class="category-info">
                <span class="category-name">{{ category.name }}</span>
                <span class="category-probability">{{ (category.probability * 100).toFixed(1) }}%</span>
              </div>
              <div class="probability-bar">
                <div 
                  class="probability-fill" 
                  :style="{ width: (category.probability * 100) + '%' }"
                  :class="getProbabilityClass(category.probability)"
                ></div>
              </div>
            </div>
          </div>
        </div>
        
        <div class="prediction-card">
          <h4>预测置信度</h4>
          <div class="confidence-display">
            <div class="confidence-circle" :class="getConfidenceClass(neuralNetworkData.confidence)">
              <div class="confidence-value">{{ (neuralNetworkData.confidence * 100).toFixed(1) }}%</div>
              <div class="confidence-label">置信度</div>
            </div>
            <div class="confidence-details">
              <div class="detail-item">
                <span class="label">最高概率类别:</span>
                <span class="value">{{ getHighestProbabilityCategory().name }}</span>
              </div>
              <div class="detail-item">
                <span class="label">预测准确率:</span>
                <span class="value">{{ (neuralNetworkData.accuracy * 100).toFixed(1) }}%</span>
              </div>
              <div class="detail-item">
                <span class="label">模型版本:</span>
                <span class="value">{{ neuralNetworkData.modelVersion }}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 数据可视化标签页 -->
    <div class="data-visualization">
      <div class="tabs">
        <button
          v-for="tab in tabs"
          :key="tab.id"
          :class="{ active: activeTab === tab.id }"
          @click="activeTab = tab.id"
        >
          {{ tab.label }}
        </button>
      </div>

      <div class="tab-content">
        <!-- 定位误差可视化 -->
        <div v-if="activeTab === 'positioning'" class="chart-container">
          <h4>定位误差分析</h4>
          <div class="chart-row">
            <div class="chart-item">
              <h5>X轴定位误差</h5>
              <div class="error-bars">
                <div 
                  v-for="(value, index) in positioningErrorX" 
                  :key="index"
                  class="error-bar"
                  :style="{ height: (value * 50) + 'px' }"
                  :class="getErrorClass(value, 'x')"
                >
                  <span class="bar-value">{{ value.toFixed(3) }}</span>
                </div>
              </div>
            </div>
            <div class="chart-item">
              <h5>Y轴定位误差</h5>
              <div class="error-bars">
                <div 
                  v-for="(value, index) in positioningErrorY" 
                  :key="index"
                  class="error-bar"
                  :style="{ height: (value * 50) + 'px' }"
                  :class="getErrorClass(value, 'y')"
                >
                  <span class="bar-value">{{ value.toFixed(3) }}</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 坐标数据可视化 -->
        <div v-if="activeTab === 'coordinates'" class="chart-container">
          <h4>坐标数据对比</h4>
          <div class="chart-row">
            <div class="chart-item">
              <h5>物件坐标 vs 物理坐标</h5>
              <div class="coordinate-display">
                <div class="coord-item">
                  <span class="coord-label">物件坐标:</span>
                  <span class="coord-value">({{ objectVsPhysical.object.x?.toFixed(2) }}, {{ objectVsPhysical.object.y?.toFixed(2) }})</span>
                </div>
                <div class="coord-item">
                  <span class="coord-label">物理坐标:</span>
                  <span class="coord-value">({{ objectVsPhysical.physical.x?.toFixed(2) }}, {{ objectVsPhysical.physical.y?.toFixed(2) }})</span>
                </div>
                <div class="coord-item">
                  <span class="coord-label">偏差:</span>
                  <span class="coord-value" :class="getDeviationClass()">
                    ({{ getDeviation('x').toFixed(2) }}, {{ getDeviation('y').toFixed(2) }})
                  </span>
                </div>
              </div>
            </div>
            <div class="chart-item">
              <h5>PLC坐标 vs 光栅反馈</h5>
              <div class="coordinate-display">
                <div class="coord-item">
                  <span class="coord-label">PLC坐标:</span>
                  <span class="coord-value">({{ plcVsGrating.plc.x?.toFixed(2) }}, {{ plcVsGrating.plc.y?.toFixed(2) }})</span>
                </div>
                <div class="coord-item">
                  <span class="coord-label">光栅反馈:</span>
                  <span class="coord-value">({{ plcVsGrating.grating.x?.toFixed(2) }}, {{ plcVsGrating.grating.y?.toFixed(2) }})</span>
                </div>
                <div class="coord-item">
                  <span class="coord-label">偏差:</span>
                  <span class="coord-value" :class="getGratingDeviationClass()">
                    ({{ getGratingDeviation('x').toFixed(2) }}, {{ getGratingDeviation('y').toFixed(2) }})
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 视觉误差可视化 -->
        <div v-if="activeTab === 'vision'" class="chart-container">
          <h4>视觉系统误差</h4>
          <div class="chart-row">
            <div class="chart-item">
              <h5>视觉误差X/Y</h5>
              <div class="vision-errors">
                <div class="error-item">
                  <span class="error-label">X轴误差:</span>
                  <div class="error-bar-container">
                    <div 
                      class="error-bar-fill" 
                      :style="{ width: (Math.abs(visionErrors.x) * 100) + '%' }"
                      :class="getVisionErrorClass('x')"
                    ></div>
                    <span class="error-value">{{ visionErrors.x?.toFixed(3) }}</span>
                  </div>
                </div>
                <div class="error-item">
                  <span class="error-label">Y轴误差:</span>
                  <div class="error-bar-container">
                    <div 
                      class="error-bar-fill" 
                      :style="{ width: (Math.abs(visionErrors.y) * 100) + '%' }"
                      :class="getVisionErrorClass('y')"
                    ></div>
                    <span class="error-value">{{ visionErrors.y?.toFixed(3) }}</span>
                  </div>
                </div>
              </div>
            </div>
            <div class="chart-item">
              <h5>贴合误差</h5>
              <div class="fitting-errors">
                <div class="error-item">
                  <span class="error-label">X轴贴合误差:</span>
                  <span class="error-value" :class="getFittingErrorClass('x')">
                    {{ fittingErrors.x?.toFixed(3) }}
                  </span>
                </div>
                <div class="error-item">
                  <span class="error-label">Y轴贴合误差:</span>
                  <span class="error-value" :class="getFittingErrorClass('y')">
                    {{ fittingErrors.y?.toFixed(3) }}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 原始数据表格 -->
        <div v-if="activeTab === 'raw'" class="raw-data-container">
          <h4>原始数据</h4>
          <div class="table-responsive">
            <table class="data-table">
              <thead>
                <tr>
                  <th v-for="header in tableHeaders" :key="header">{{ header }}</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td v-for="(value, key) in rawData" :key="key">{{ value }}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>

    <!-- 操作按钮 -->
    <div class="actions">
      <button class="refresh-btn" @click="refreshData">
        <i class="fas fa-sync-alt"></i> 刷新数据
      </button>
      <button class="export-btn" @click="exportReport">
        <i class="fas fa-file-export"></i> 导出报告
      </button>
    </div>
  </div>
</template>

<script>
import { ref, computed, onMounted, onUnmounted } from 'vue'
import axios from 'axios'
import { saveAs } from 'file-saver'

export default {
  name: 'FaultDiagnosis',
  setup() {
    const activeTab = ref('positioning')
    const diagnosisResult = ref('等待诊断结果...')
    const rawData = ref({})
    const isLoading = ref(false)
    const faultCategories = ref([])
    const neuralNetworkData = ref({})

    // 标签页配置
    const tabs = [
      { id: 'positioning', label: '定位误差' },
      { id: 'coordinates', label: '坐标对比' },
      { id: 'vision', label: '视觉误差' },
      { id: 'raw', label: '原始数据' }
    ]

    // 计算属性
    const diagnosisStatus = computed(() => {
      if (isLoading.value) return 'loading'
      if (!diagnosisResult.value || diagnosisResult.value.includes('等待')) return 'idle'
      if (diagnosisResult.value.includes('正常')) return 'normal'
      if (diagnosisResult.value.includes('警告')) return 'warning'
      return 'error'
    })

    const statusText = computed(() => {
      switch (diagnosisStatus.value) {
        case 'loading': return '诊断中...'
        case 'idle': return '待诊断'
        case 'normal': return '状态正常'
        case 'warning': return '存在警告'
        case 'error': return '发现故障'
        default: return '未知状态'
      }
    })

    const resultCardClass = computed(() => {
      return `result-${diagnosisStatus.value}`
    })

    // 图表数据计算
    const positioningErrorX = computed(() => {
      return [
        rawData.value['all定位误差X-1'] || 0,
        rawData.value['all定位误差X-2'] || 0,
        rawData.value['all定位误差X-3'] || 0,
        rawData.value['all定位误差X-4'] || 0
      ]
    })

    const positioningErrorY = computed(() => {
      return [
        rawData.value['all定位误差Y-1'] || 0,
        rawData.value['all定位误差Y-2'] || 0,
        rawData.value['all定位误差Y-3'] || 0,
        rawData.value['all定位误差Y-4'] || 0
      ]
    })

    const objectVsPhysical = computed(() => {
      return {
        object: {
          x: rawData.value['all物件坐标X-1'] || 0,
          y: rawData.value['all物件坐标Y-1'] || 0
        },
        physical: {
          x: rawData.value['all物理坐标X-1'] || 0,
          y: rawData.value['all物理坐标Y-1'] || 0
        }
      }
    })

    const plcVsGrating = computed(() => {
      return {
        plc: {
          x: rawData.value['catchPLC坐标X'] || 0,
          y: rawData.value['catchPLC坐标Y'] || 0
        },
        grating: {
          x: rawData.value['catch光栅反馈X'] || 0,
          y: rawData.value['catch光栅反馈Y'] || 0
        }
      }
    })

    const visionErrors = computed(() => {
      return {
        x: rawData.value['视觉误差X'] || 0,
        y: rawData.value['视觉误差Y'] || 0
      }
    })

    const fittingErrors = computed(() => {
      return {
        x: rawData.value['贴合误差X'] || 0,
        y: rawData.value['贴合误差Y'] || 0
      }
    })

    const tableHeaders = computed(() => {
      return Object.keys(rawData.value)
    })

    // 方法
    const getErrorClass = (value, axis) => {
      const threshold = axis === 'x' ? 1.5 : 1.5
      if (value > threshold) return 'danger'
      if (value > threshold * 0.8) return 'warning'
      return 'normal'
    }

    const getDeviation = (axis) => {
      const object = objectVsPhysical.value.object
      const physical = objectVsPhysical.value.physical
      return axis === 'x' ? object.x - physical.x : object.y - physical.y
    }

    const getDeviationClass = () => {
      const deviation = Math.sqrt(getDeviation('x') ** 2 + getDeviation('y') ** 2)
      if (deviation > 2) return 'danger'
      if (deviation > 1) return 'warning'
      return 'normal'
    }

    const getGratingDeviation = (axis) => {
      const plc = plcVsGrating.value.plc
      const grating = plcVsGrating.value.grating
      return axis === 'x' ? plc.x - grating.x : plc.y - grating.y
    }

    const getGratingDeviationClass = () => {
      const deviation = Math.sqrt(getGratingDeviation('x') ** 2 + getGratingDeviation('y') ** 2)
      if (deviation > 2) return 'danger'
      if (deviation > 1) return 'warning'
      return 'normal'
    }

    const getVisionErrorClass = (axis) => {
      const value = Math.abs(axis === 'x' ? visionErrors.value.x : visionErrors.value.y)
      if (value > 0.8) return 'danger'
      if (value > 0.5) return 'warning'
      return 'normal'
    }

    const getFittingErrorClass = (axis) => {
      const value = Math.abs(axis === 'x' ? fittingErrors.value.x : fittingErrors.value.y)
      if (value > 0.8) return 'danger'
      if (value > 0.5) return 'warning'
      return 'normal'
    }

    // 神经网络预测相关方法
    const getProbabilityClass = (probability) => {
      if (probability > 0.8) return 'high'
      if (probability > 0.6) return 'medium'
      if (probability > 0.4) return 'low'
      return 'very-low'
    }

    const getConfidenceClass = (confidence) => {
      if (confidence > 0.9) return 'excellent'
      if (confidence > 0.7) return 'good'
      if (confidence > 0.5) return 'fair'
      return 'poor'
    }

    const getHighestProbabilityCategory = () => {
      if (faultCategories.value.length === 0) return { name: '无数据', probability: 0 }
      return faultCategories.value.reduce((max, category) => 
        category.probability > max.probability ? category : max
      )
    }

    const fetchDiagnosisData = async () => {
      isLoading.value = true
      try {
        const response = await axios.get('/api/maintenance/diagnosis')
        if (response.data.status === 'success') {
          diagnosisResult.value = response.data.result
          rawData.value = response.data.data
          
          // 从响应中获取神经网络预测概率数据
          if (response.data.probabilities && Array.isArray(response.data.probabilities)) {
            // 将概率数据转换为前端需要的格式
            faultCategories.value = response.data.probabilities.map(item => ({
              name: item.label,
              probability: item.probability / 100  // 后端返回的是百分比，需要转换为0-1之间
            }))
            
            // 计算置信度和准确率
            const maxProb = Math.max(...faultCategories.value.map(cat => cat.probability))
            
            // 如果后端返回了置信度，使用后端的置信度；否则使用最大概率
            let confidenceValue = maxProb
            if (response.data.confidence) {
              // 置信度可能是 "60.66%" 格式，需要解析
              const confStr = String(response.data.confidence).replace('%', '')
              const confNum = parseFloat(confStr)
              if (!isNaN(confNum)) {
                confidenceValue = confNum / 100
              }
            }
            
            neuralNetworkData.value = {
              confidence: confidenceValue,
              accuracy: maxProb,
              modelVersion: 'v1.0.0',
              lastUpdated: new Date().toISOString()
            }
          } else {
            // 如果没有概率数据，使用模拟数据
            generateMockNeuralData()
          }
        } else {
          diagnosisResult.value = '诊断失败: ' + (response.data.message || '未知错误')
        }
      } catch (error) {
        console.error('获取诊断数据失败:', error)
        diagnosisResult.value = '诊断失败: ' + (error.response?.data?.message || error.message)
      } finally {
        isLoading.value = false
      }
    }

    const generateMockNeuralData = () => {
      // 生成模拟的故障类别概率
      const categories = [
        { name: 'X轴定位精度异常', probability: Math.random() * 0.4 + 0.3 },
        { name: 'Y轴定位精度异常', probability: Math.random() * 0.3 + 0.2 },
        { name: '视觉系统误差', probability: Math.random() * 0.2 + 0.1 },
        { name: '贴合精度异常', probability: Math.random() * 0.15 + 0.05 },
        { name: '机械磨损', probability: Math.random() * 0.1 + 0.02 },
        { name: '电气故障', probability: Math.random() * 0.08 + 0.01 },
        { name: '环境干扰', probability: Math.random() * 0.05 + 0.005 },
        { name: '正常状态', probability: Math.random() * 0.1 + 0.01 }
      ]
      
      // 归一化概率
      const total = categories.reduce((sum, cat) => sum + cat.probability, 0)
      faultCategories.value = categories.map(cat => ({
        ...cat,
        probability: cat.probability / total
      }))
      
      // 按概率排序
      faultCategories.value.sort((a, b) => b.probability - a.probability)
      
      // 生成元数据
      neuralNetworkData.value = {
        confidence: Math.random() * 0.3 + 0.7,
        accuracy: Math.random() * 0.2 + 0.8,
        modelVersion: 'v2.1.3',
        lastUpdated: new Date().toISOString()
      }
    }

    const refreshData = () => {
      fetchDiagnosisData()
    }

    const exportReport = () => {
      const blob = new Blob([generateReport()], { type: 'text/plain;charset=utf-8' })
      saveAs(blob, `诊断报告_${new Date().toISOString().slice(0,10)}.txt`)
    }

    const generateReport = () => {
      let report = `设备故障诊断报告\n生成时间: ${new Date().toLocaleString()}\n\n`
      report += `诊断结果: ${diagnosisResult.value}\n\n`
      report += '详细数据:\n'

      for (const [key, value] of Object.entries(rawData.value)) {
        report += `${key}: ${value}\n`
      }

      return report
    }

    let diagnosisIntervalId = null
    
    onMounted(() => {
      // 立即获取一次数据
      fetchDiagnosisData()
      
      // 设置每2秒自动刷新一次
      diagnosisIntervalId = setInterval(() => {
        fetchDiagnosisData()
      }, 2000)  // 2000毫秒 = 2秒
    })
    
    onUnmounted(() => {
      // 组件卸载时清除定时器
      if (diagnosisIntervalId) {
        clearInterval(diagnosisIntervalId)
      }
    })

    return {
      activeTab,
      tabs,
      diagnosisResult,
      rawData,
      diagnosisStatus,
      statusText,
      resultCardClass,
      positioningErrorX,
      positioningErrorY,
      objectVsPhysical,
      plcVsGrating,
      visionErrors,
      fittingErrors,
      tableHeaders,
      faultCategories,
      neuralNetworkData,
      getErrorClass,
      getDeviation,
      getDeviationClass,
      getGratingDeviation,
      getGratingDeviationClass,
      getVisionErrorClass,
      getFittingErrorClass,
      getProbabilityClass,
      getConfidenceClass,
      getHighestProbabilityCategory,
      refreshData,
      exportReport
    }
  }
}
</script>

